@page "/settings"
@rendermode InteractiveServer
@using sv_d3db0153abd043ff8615604b49955c4a.Models
@using sv_d3db0153abd043ff8615604b49955c4a.Services
@inject ISettingsService SettingsService

<PageTitle>Settings</PageTitle>

<div class="settings-container">
    <nav class="settings-sidebar">
        <h4 class="sidebar-title">Settings</h4>
        <ul class="nav flex-column">
            @foreach (var section in _sections)
            {
                <li class="nav-item">
                    <button class="nav-link @(ActiveSection == section.Key ? "active" : "")"
                            @onclick="() => SetActiveSection(section.Key)">
                        <span class="section-icon">@section.Value.Icon</span>
                        @section.Value.Label
                    </button>
                </li>
            }
        </ul>
    </nav>

    <main class="settings-content">
        @if (_loading)
        {
            <div class="d-flex justify-content-center p-5">
                <div class="spinner-border text-primary" role="status">
                    <span class="visually-hidden">Loading...</span>
                </div>
            </div>
        }
        else
        {
            @switch (ActiveSection)
            {
                case "profile":
                    @RenderProfileSection()
                    break;
                case "notifications":
                    @RenderNotificationsSection()
                    break;
                case "security":
                    @RenderSecuritySection()
                    break;
                case "appearance":
                    @RenderAppearanceSection()
                    break;
            }
        }

        @if (!string.IsNullOrEmpty(_toastMessage))
        {
            <div class="settings-toast @(_toastIsError ? "toast-error" : "toast-success")">
                <span>@_toastMessage</span>
                <button class="btn-close btn-close-white btn-sm" @onclick="DismissToast"></button>
            </div>
        }
    </main>
</div>

@* ───── Profile Section ───── *@
@{
    RenderFragment RenderProfileSection() =>
        @<section class="settings-section">
            <h3>Profile</h3>
            <p class="text-muted">Manage your public profile information.</p>
            <hr />

            <div class="avatar-area mb-4">
                <div class="avatar-preview">
                    @if (!string.IsNullOrWhiteSpace(_profileAvatarUrl))
                    {
                        <img src="@_profileAvatarUrl" alt="Avatar" />
                    }
                    else
                    {
                        <span class="avatar-placeholder">👤</span>
                    }
                </div>
                <div class="avatar-url-display">
                    <label class="form-label">Avatar URL</label>
                    <input type="url" class="form-control" value="@_profileAvatarUrl"
                           @oninput="e => _profileAvatarUrl = e.Value?.ToString() ?? string.Empty" />
                </div>
            </div>

            <div class="mb-3">
                <label class="form-label">Display Name</label>
                <input type="text" class="form-control" @bind="_profileDisplayName" />
            </div>
            <div class="mb-3">
                <label class="form-label">Email</label>
                <input type="email" class="form-control" @bind="_profileEmail" />
            </div>
            <div class="mb-3">
                <label class="form-label">Bio</label>
                <textarea class="form-control" rows="4" @bind="_profileBio"></textarea>
            </div>

            <div class="d-flex gap-2">
                <button class="btn btn-primary" @onclick="SaveProfile" disabled="@_saving">
                    @if (_saving) { <span class="spinner-border spinner-border-sm me-1"></span> }
                    Save Changes
                </button>
                <button class="btn btn-outline-secondary" @onclick="DiscardProfileChanges" disabled="@_saving">
                    Discard Changes
                </button>
            </div>
        </section>;
}

@* ───── Notifications Section ───── *@
@{
    RenderFragment RenderNotificationsSection() =>
        @<section class="settings-section">
            <h3>Notifications</h3>
            <p class="text-muted">Choose how and when you want to be notified.</p>
            <hr />

            <div class="toggle-row">
                <div>
                    <strong>Email Notifications</strong>
                    <p class="text-muted mb-0">Receive updates via email.</p>
                </div>
                <div class="form-check form-switch">
                    <input class="form-check-input" type="checkbox" role="switch"
                           checked="@_notifEmail" @onchange="e => _notifEmail = (bool)(e.Value ?? false)" />
                </div>
            </div>
            <div class="toggle-row">
                <div>
                    <strong>Push Notifications</strong>
                    <p class="text-muted mb-0">Receive browser push notifications.</p>
                </div>
                <div class="form-check form-switch">
                    <input class="form-check-input" type="checkbox" role="switch"
                           checked="@_notifPush" @onchange="e => _notifPush = (bool)(e.Value ?? false)" />
                </div>
            </div>
            <div class="toggle-row">
                <div>
                    <strong>Weekly Digest</strong>
                    <p class="text-muted mb-0">Get a summary email every week.</p>
                </div>
                <div class="form-check form-switch">
                    <input class="form-check-input" type="checkbox" role="switch"
                           checked="@_notifDigest" @onchange="e => _notifDigest = (bool)(e.Value ?? false)" />
                </div>
            </div>

            <h5 class="mt-4 mb-3">Muted Channels</h5>
            @if (_allChannels.Count > 0)
            {
                <div class="channel-list">
                    @foreach (var channel in _allChannels)
                    {
                        var isMuted = _mutedChannels.Contains(channel);
                        <div class="form-check">
                            <input class="form-check-input" type="checkbox" id="ch-@channel"
                                   checked="@isMuted"
                                   @onchange="e => ToggleMuteChannel(channel, (bool)(e.Value ?? false))" />
                            <label class="form-check-label" for="ch-@channel">@channel</label>
                        </div>
                    }
                </div>
            }
            else
            {
                <p class="text-muted fst-italic">No channels available.</p>
            }

            <div class="mt-4">
                <button class="btn btn-primary" @onclick="SaveNotifications" disabled="@_saving">
                    @if (_saving) { <span class="spinner-border spinner-border-sm me-1"></span> }
                    Save Preferences
                </button>
            </div>
        </section>;
}

@* ───── Security Section ───── *@
@{
    RenderFragment RenderSecuritySection() =>
        @<section class="settings-section">
            <h3>Security</h3>
            <p class="text-muted">Manage your password, two-factor authentication, and sessions.</p>
            <hr />

            @* Change Password Panel *@
            <div class="expandable-panel mb-4">
                <button class="expandable-header" @onclick="() => _passwordPanelOpen = !_passwordPanelOpen">
                    <span>🔑 Change Password</span>
                    <span class="expand-icon">@(_passwordPanelOpen ? "▲" : "▼")</span>
                </button>
                @if (_passwordPanelOpen)
                {
                    <div class="expandable-body">
                        <div class="mb-3">
                            <label class="form-label">Current Password</label>
                            <input type="password" class="form-control" @bind="_currentPassword" />
                        </div>
                        <div class="mb-3">
                            <label class="form-label">New Password</label>
                            <input type="password" class="form-control" @bind="_newPassword" />
                        </div>
                        <div class="mb-3">
                            <label class="form-label">Confirm New Password</label>
                            <input type="password" class="form-control" @bind="_confirmPassword" />
                        </div>
                        <button class="btn btn-warning" @onclick="ChangePassword" disabled="@_saving">
                            @if (_saving) { <span class="spinner-border spinner-border-sm me-1"></span> }
                            Update Password
                        </button>
                    </div>
                }
            </div>

            @* Two-Factor Authentication *@
            <div class="toggle-row mb-4">
                <div>
                    <strong>Two-Factor Authentication</strong>
                    <p class="text-muted mb-0">
                        Status:
                        <span class="badge @(_twoFactorEnabled ? "bg-success" : "bg-secondary")">
                            @(_twoFactorEnabled ? "Enabled" : "Disabled")
                        </span>
                    </p>
                </div>
                <div class="form-check form-switch">
                    <input class="form-check-input" type="checkbox" role="switch"
                           checked="@_twoFactorEnabled"
                           @onchange="e => _twoFactorEnabled = (bool)(e.Value ?? false)" />
                </div>
            </div>

            @if (_securitySettings?.LastPasswordChange is not null)
            {
                <p class="text-muted">
                    <small>Last password change: @_securitySettings.LastPasswordChange.Value.ToString("MMMM dd, yyyy")</small>
                </p>
            }

            @* Active Sessions *@
            <h5 class="mt-4 mb-3">Active Sessions</h5>
            @if (_sessions.Count > 0)
            {
                <div class="table-responsive">
                    <table class="table table-hover align-middle">
                        <thead class="table-light">
                            <tr>
                                <th>Device</th>
                                <th>Location</th>
                                <th>Last Active</th>
                                <th></th>
                            </tr>
                        </thead>
                        <tbody>
                            @foreach (var session in _sessions)
                            {
                                var isCurrent = session == _sessions.FirstOrDefault();
                                <tr>
                                    <td>
                                        @session.Device
                                        @if (isCurrent) { <span class="badge bg-info ms-1">Current</span> }
                                    </td>
                                    <td>@session.Location</td>
                                    <td>@session.LastActive.ToString("g")</td>
                                    <td>
                                        @if (!isCurrent)
                                        {
                                            <button class="btn btn-outline-danger btn-sm"
                                                    @onclick="() => PromptRevokeSession(session)">
                                                Revoke
                                            </button>
                                        }
                                    </td>
                                </tr>
                            }
                        </tbody>
                    </table>
                </div>
            }
            else
            {
                <p class="text-muted fst-italic">No active sessions found.</p>
            }

            @* Revoke Confirmation Dialog *@
            @if (_sessionToRevoke is not null)
            {
                <div class="modal-backdrop-custom" @onclick="CancelRevoke">
                    <div class="confirm-dialog" @onclick:stopPropagation="true">
                        <h5>Revoke Session</h5>
                        <p>Are you sure you want to revoke the session on <strong>@_sessionToRevoke.Device</strong> in <strong>@_sessionToRevoke.Location</strong>?</p>
                        <div class="d-flex gap-2 justify-content-end">
                            <button class="btn btn-outline-secondary btn-sm" @onclick="CancelRevoke">Cancel</button>
                            <button class="btn btn-danger btn-sm" @onclick="ConfirmRevokeSession" disabled="@_saving">
                                @if (_saving) { <span class="spinner-border spinner-border-sm me-1"></span> }
                                Revoke
                            </button>
                        </div>
                    </div>
                </div>
            }
        </section>;
}

@* ───── Appearance Section ───── *@
@{
    RenderFragment RenderAppearanceSection() =>
        @<section class="settings-section">
            <h3>Appearance</h3>
            <p class="text-muted">Customize how the application looks and feels.</p>
            <hr />

            <div class="row">
                <div class="col-md-7">
                    @* Theme *@
                    <h5 class="mb-3">Theme</h5>
                    <div class="d-flex gap-3 mb-4">
                        @foreach (var theme in new[] { "Light", "Dark", "System" })
                        {
                            <div class="form-check">
                                <input class="form-check-input" type="radio" name="theme" id="theme-@theme"
                                       value="@theme" checked="@(_appearanceTheme == theme)"
                                       @onchange="() => _appearanceTheme = theme" />
                                <label class="form-check-label" for="theme-@theme">@theme</label>
                            </div>
                        }
                    </div>

                    @* Font Size *@
                    <h5 class="mb-3">Font Size</h5>
                    <div class="d-flex gap-3 mb-4">
                        @foreach (var size in new[] { "Small", "Medium", "Large" })
                        {
                            <div class="form-check">
                                <input class="form-check-input" type="radio" name="fontSize" id="fs-@size"
                                       value="@size" checked="@(_appearanceFontSize == size)"
                                       @onchange="() => _appearanceFontSize = size" />
                                <label class="form-check-label" for="fs-@size">@size</label>
                            </div>
                        }
                    </div>

                    @* Language *@
                    <div class="mb-4">
                        <h5 class="mb-3">Language</h5>
                        <select class="form-select" style="max-width: 300px;"
                                value="@_appearanceLanguage"
                                @onchange="e => _appearanceLanguage = e.Value?.ToString() ?? "English"">
                            @foreach (var lang in _availableLanguages)
                            {
                                <option value="@lang">@lang</option>
                            }
                        </select>
                    </div>

                    @* Compact Mode *@
                    <div class="toggle-row mb-4">
                        <div>
                            <strong>Compact Mode</strong>
                            <p class="text-muted mb-0">Reduce spacing and padding throughout the UI.</p>
                        </div>
                        <div class="form-check form-switch">
                            <input class="form-check-input" type="checkbox" role="switch"
                                   checked="@_appearanceCompact"
                                   @onchange="e => _appearanceCompact = (bool)(e.Value ?? false)" />
                        </div>
                    </div>

                    <button class="btn btn-primary" @onclick="SaveAppearance" disabled="@_saving">
                        @if (_saving) { <span class="spinner-border spinner-border-sm me-1"></span> }
                        Save
                    </button>
                </div>

                @* Live Preview *@
                <div class="col-md-5">
                    <h5 class="mb-3">Preview</h5>
                    <div class="appearance-preview @GetPreviewClasses()">
                        <div class="preview-header">Header</div>
                        <div class="preview-body">
                            <p class="preview-text">This is a preview of your selected appearance settings.</p>
                            <button class="preview-button">Sample Button</button>
                        </div>
                        <div class="preview-footer">Footer</div>
                    </div>
                </div>
            </div>
        </section>;
}

@code {
    // ───── Section navigation ─────
    private string ActiveSection { get; set; } = "profile";
    private bool _loading = true;
    private bool _saving;

    private readonly Dictionary<string, (string Label, string Icon)> _sections = new()
    {
        ["profile"] = ("Profile", "👤"),
        ["notifications"] = ("Notifications", "🔔"),
        ["security"] = ("Security", "🛡️"),
        ["appearance"] = ("Appearance", "🎨")
    };

    // ───── Toast ─────
    private string? _toastMessage;
    private bool _toastIsError;
    private CancellationTokenSource? _toastCts;

    // ───── Profile state ─────
    private string _profileDisplayName = string.Empty;
    private string _profileEmail = string.Empty;
    private string _profileAvatarUrl = string.Empty;
    private string _profileBio = string.Empty;
    private UserProfile? _savedProfile;

    // ───── Notifications state ─────
    private bool _notifEmail;
    private bool _notifPush;
    private bool _notifDigest;
    private HashSet<string> _mutedChannels = new();
    private readonly List<string> _allChannels = new()
    {
        "general", "announcements", "engineering", "design", "marketing", "random", "support"
    };

    // ───── Security state ─────
    private SecuritySettings? _securitySettings;
    private bool _passwordPanelOpen;
    private string _currentPassword = string.Empty;
    private string _newPassword = string.Empty;
    private string _confirmPassword = string.Empty;
    private bool _twoFactorEnabled;
    private List<ActiveSession> _sessions = new();
    private ActiveSession? _sessionToRevoke;

    // ───── Appearance state ─────
    private string _appearanceTheme = "System";
    private string _appearanceFontSize = "Medium";
    private string _appearanceLanguage = "English";
    private bool _appearanceCompact;
    private readonly List<string> _availableLanguages = new()
    {
        "English", "Spanish", "French", "German", "Japanese", "Chinese", "Korean", "Portuguese"
    };

    protected override async Task OnInitializedAsync()
    {
        await LoadAllSettings();
        _loading = false;
    }

    private async Task LoadAllSettings()
    {
        var profileTask = SettingsService.GetProfileAsync();
        var notifTask = SettingsService.GetNotificationPrefsAsync();
        var securityTask = SettingsService.GetSecuritySettingsAsync();
        var appearanceTask = SettingsService.GetAppearanceAsync();

        await Task.WhenAll(profileTask, notifTask, securityTask, appearanceTask);

        ApplyProfile(await profileTask);
        ApplyNotifications(await notifTask);
        ApplySecurity(await securityTask);
        ApplyAppearance(await appearanceTask);
    }

    // ───── Section switching ─────
    private void SetActiveSection(string section) => ActiveSection = section;

    // ───── Profile ─────
    private void ApplyProfile(UserProfile profile)
    {
        _savedProfile = profile;
        _profileDisplayName = profile.DisplayName;
        _profileEmail = profile.Email;
        _profileAvatarUrl = profile.AvatarUrl;
        _profileBio = profile.Bio;
    }

    private async Task SaveProfile()
    {
        _saving = true;
        try
        {
            var profile = new UserProfile(_profileDisplayName, _profileEmail, _profileAvatarUrl, _profileBio);
            await SettingsService.SaveProfileAsync(profile);
            _savedProfile = profile;
            ShowToast("Profile saved successfully.");
        }
        catch (Exception ex)
        {
            ShowToast($"Failed to save profile: {ex.Message}", isError: true);
        }
        finally
        {
            _saving = false;
        }
    }

    private void DiscardProfileChanges()
    {
        if (_savedProfile is not null)
        {
            ApplyProfile(_savedProfile);
        }
    }

    // ───── Notifications ─────
    private void ApplyNotifications(NotificationPrefs prefs)
    {
        _notifEmail = prefs.EmailNotifications;
        _notifPush = prefs.PushNotifications;
        _notifDigest = prefs.WeeklyDigest;
        _mutedChannels = new HashSet<string>(prefs.MutedChannels);
    }

    private void ToggleMuteChannel(string channel, bool muted)
    {
        if (muted)
            _mutedChannels.Add(channel);
        else
            _mutedChannels.Remove(channel);
    }

    private async Task SaveNotifications()
    {
        _saving = true;
        try
        {
            var prefs = new NotificationPrefs(_notifEmail, _notifPush, _notifDigest, _mutedChannels.ToList());
            await SettingsService.SaveNotificationPrefsAsync(prefs);
            ShowToast("Notification preferences saved.");
        }
        catch (Exception ex)
        {
            ShowToast($"Failed to save preferences: {ex.Message}", isError: true);
        }
        finally
        {
            _saving = false;
        }
    }

    // ───── Security ─────
    private void ApplySecurity(SecuritySettings settings)
    {
        _securitySettings = settings;
        _twoFactorEnabled = settings.TwoFactorEnabled;
        _sessions = new List<ActiveSession>(settings.Sessions);
    }

    private async Task ChangePassword()
    {
        if (string.IsNullOrWhiteSpace(_currentPassword) ||
            string.IsNullOrWhiteSpace(_newPassword) ||
            string.IsNullOrWhiteSpace(_confirmPassword))
        {
            ShowToast("All password fields are required.", isError: true);
            return;
        }

        if (_newPassword != _confirmPassword)
        {
            ShowToast("New password and confirmation do not match.", isError: true);
            return;
        }

        _saving = true;
        try
        {
            await SettingsService.ChangePasswordAsync(_currentPassword, _newPassword);
            _currentPassword = string.Empty;
            _newPassword = string.Empty;
            _confirmPassword = string.Empty;
            _passwordPanelOpen = false;
            ShowToast("Password updated successfully.");
        }
        catch (Exception ex)
        {
            ShowToast($"Failed to change password: {ex.Message}", isError: true);
        }
        finally
        {
            _saving = false;
        }
    }

    private void PromptRevokeSession(ActiveSession session) => _sessionToRevoke = session;

    private void CancelRevoke() => _sessionToRevoke = null;

    private async Task ConfirmRevokeSession()
    {
        if (_sessionToRevoke is null) return;

        _saving = true;
        try
        {
            await SettingsService.RevokeSessionAsync(_sessionToRevoke.Id);
            _sessions.Remove(_sessionToRevoke);
            ShowToast($"Session on {_sessionToRevoke.Device} revoked.");
            _sessionToRevoke = null;
        }
        catch (Exception ex)
        {
            ShowToast($"Failed to revoke session: {ex.Message}", isError: true);
        }
        finally
        {
            _saving = false;
        }
    }

    // ───── Appearance ─────
    private void ApplyAppearance(AppearanceSettings settings)
    {
        _appearanceTheme = settings.Theme;
        _appearanceFontSize = settings.FontSize;
        _appearanceLanguage = settings.Language;
        _appearanceCompact = settings.CompactMode;
    }

    private async Task SaveAppearance()
    {
        _saving = true;
        try
        {
            var settings = new AppearanceSettings(_appearanceTheme, _appearanceFontSize, _appearanceLanguage, _appearanceCompact);
            await SettingsService.SaveAppearanceAsync(settings);
            ShowToast("Appearance settings saved.");
        }
        catch (Exception ex)
        {
            ShowToast($"Failed to save appearance: {ex.Message}", isError: true);
        }
        finally
        {
            _saving = false;
        }
    }

    private string GetPreviewClasses()
    {
        var classes = new List<string>();
        classes.Add(_appearanceTheme switch
        {
            "Dark" => "preview-dark",
            "Light" => "preview-light",
            _ => "preview-system"
        });
        classes.Add(_appearanceFontSize switch
        {
            "Small" => "preview-font-sm",
            "Large" => "preview-font-lg",
            _ => "preview-font-md"
        });
        if (_appearanceCompact) classes.Add("preview-compact");
        return string.Join(" ", classes);
    }

    // ───── Toast helpers ─────
    private void ShowToast(string message, bool isError = false)
    {
        _toastCts?.Cancel();
        _toastMessage = message;
        _toastIsError = isError;
        _toastCts = new CancellationTokenSource();
        _ = AutoDismissToast(_toastCts.Token);
    }

    private async Task AutoDismissToast(CancellationToken token)
    {
        try
        {
            await Task.Delay(4000, token);
            _toastMessage = null;
            await InvokeAsync(StateHasChanged);
        }
        catch (TaskCanceledException) { }
    }

    private void DismissToast()
    {
        _toastCts?.Cancel();
        _toastMessage = null;
    }
}

.settings-container {
    display: flex;
    min-height: calc(100vh - 4rem);
    gap: 0;
}

/* ───── Sidebar ───── */
.settings-sidebar {
    width: 240px;
    flex-shrink: 0;
    background: #f8f9fa;
    border-right: 1px solid #dee2e6;
    padding: 1.5rem 0;
}

.sidebar-title {
    padding: 0 1.25rem 1rem;
    margin: 0;
    font-weight: 600;
    color: #495057;
    font-size: 1.1rem;
}

.settings-sidebar .nav-link {
    display: flex;
    align-items: center;
    gap: 0.6rem;
    padding: 0.65rem 1.25rem;
    color: #495057;
    border: none;
    background: none;
    width: 100%;
    text-align: left;
    font-size: 0.95rem;
    border-left: 3px solid transparent;
    transition: background-color 0.15s, border-color 0.15s;
    cursor: pointer;
}

.settings-sidebar .nav-link:hover {
    background: #e9ecef;
}

.settings-sidebar .nav-link.active {
    background: #e7f1ff;
    color: #0d6efd;
    border-left-color: #0d6efd;
    font-weight: 600;
}

.section-icon {
    font-size: 1.1rem;
}

/* ───── Content ───── */
.settings-content {
    flex: 1;
    padding: 2rem 2.5rem;
    position: relative;
    max-width: 960px;
}

.settings-section h3 {
    font-weight: 600;
    margin-bottom: 0.25rem;
}

/* ───── Toggle rows ───── */
.toggle-row {
    display: flex;
    justify-content: space-between;
    align-items: center;
    padding: 0.75rem 0;
    border-bottom: 1px solid #f0f0f0;
}

.toggle-row .form-check-input {
    width: 2.5em;
    height: 1.25em;
}

/* ───── Avatar ───── */
.avatar-area {
    display: flex;
    align-items: flex-start;
    gap: 1.5rem;
}

.avatar-preview {
    width: 96px;
    height: 96px;
    border-radius: 50%;
    overflow: hidden;
    border: 2px solid #dee2e6;
    display: flex;
    align-items: center;
    justify-content: center;
    background: #f0f0f0;
    flex-shrink: 0;
}

.avatar-preview img {
    width: 100%;
    height: 100%;
    object-fit: cover;
}

.avatar-placeholder {
    font-size: 2.5rem;
}

.avatar-url-display {
    flex: 1;
    min-width: 0;
}

/* ───── Channel list ───── */
.channel-list {
    display: grid;
    grid-template-columns: repeat(auto-fill, minmax(180px, 1fr));
    gap: 0.25rem 1rem;
}

/* ───── Expandable panel ───── */
.expandable-panel {
    border: 1px solid #dee2e6;
    border-radius: 0.5rem;
    overflow: hidden;
}

.expandable-header {
    display: flex;
    justify-content: space-between;
    align-items: center;
    width: 100%;
    padding: 0.85rem 1rem;
    background: #f8f9fa;
    border: none;
    font-size: 1rem;
    font-weight: 500;
    cursor: pointer;
    transition: background-color 0.15s;
}

.expandable-header:hover {
    background: #e9ecef;
}

.expand-icon {
    font-size: 0.8rem;
    color: #6c757d;
}

.expandable-body {
    padding: 1rem;
    border-top: 1px solid #dee2e6;
}

/* ───── Confirmation dialog ───── */
.modal-backdrop-custom {
    position: fixed;
    inset: 0;
    background: rgba(0, 0, 0, 0.4);
    display: flex;
    align-items: center;
    justify-content: center;
    z-index: 1050;
}

.confirm-dialog {
    background: white;
    padding: 1.5rem;
    border-radius: 0.5rem;
    box-shadow: 0 8px 32px rgba(0, 0, 0, 0.2);
    max-width: 420px;
    width: 90%;
}

/* ───── Toast ───── */
.settings-toast {
    position: fixed;
    bottom: 1.5rem;
    right: 1.5rem;
    padding: 0.75rem 1.25rem;
    border-radius: 0.5rem;
    color: white;
    display: flex;
    align-items: center;
    gap: 0.75rem;
    box-shadow: 0 4px 16px rgba(0, 0, 0, 0.15);
    z-index: 1100;
    animation: toast-slide-in 0.3s ease;
}

.toast-success {
    background: #198754;
}

.toast-error {
    background: #dc3545;
}

@keyframes toast-slide-in {
    from {
        transform: translateY(1rem);
        opacity: 0;
    }
    to {
        transform: translateY(0);
        opacity: 1;
    }
}

/* ───── Appearance preview ───── */
.appearance-preview {
    border: 1px solid #dee2e6;
    border-radius: 0.5rem;
    overflow: hidden;
    transition: all 0.2s ease;
}

.preview-header {
    padding: 0.75rem 1rem;
    font-weight: 600;
    border-bottom: 1px solid #dee2e6;
}

.preview-body {
    padding: 1rem;
}

.preview-footer {
    padding: 0.5rem 1rem;
    border-top: 1px solid #dee2e6;
    font-size: 0.85em;
}

.preview-button {
    padding: 0.35rem 1rem;
    border-radius: 0.35rem;
    border: 1px solid #0d6efd;
    background: #0d6efd;
    color: white;
    cursor: default;
}

/* Theme variants */
.preview-light {
    background: #ffffff;
    color: #212529;
}

.preview-light .preview-header {
    background: #f8f9fa;
}

.preview-light .preview-footer {
    background: #f8f9fa;
}

.preview-dark {
    background: #1e1e2e;
    color: #cdd6f4;
    border-color: #45475a;
}

.preview-dark .preview-header {
    background: #181825;
    border-color: #45475a;
}

.preview-dark .preview-footer {
    background: #181825;
    border-color: #45475a;
}

.preview-dark .preview-button {
    background: #89b4fa;
    border-color: #89b4fa;
    color: #1e1e2e;
}

.preview-system {
    background: linear-gradient(135deg, #ffffff 50%, #1e1e2e 50%);
    color: #212529;
}

.preview-system .preview-header {
    background: #f8f9fa;
}

.preview-system .preview-footer {
    background: #f8f9fa;
}

/* Font size variants */
.preview-font-sm {
    font-size: 0.8rem;
}

.preview-font-md {
    font-size: 1rem;
}

.preview-font-lg {
    font-size: 1.2rem;
}

/* Compact mode */
.preview-compact .preview-header {
    padding: 0.4rem 0.75rem;
}

.preview-compact .preview-body {
    padding: 0.5rem 0.75rem;
}

.preview-compact .preview-footer {
    padding: 0.25rem 0.75rem;
}

.preview-compact .preview-text {
    margin-bottom: 0.25rem;
}

toolCalls.args:
{"file_text": "@page "/settings"
@rendermode InteractiveServer
@using sv_d3db0153abd043ff8615604b49955c4a.Models
@using sv_d3db0153abd043ff8615604b49955c4a.Services
@inject ISettingsService SettingsService

<PageTitle>Settings</PageTitle>

<div class="settings-container">
    <nav class="settings-sidebar">
        <h4 class="sidebar-title">Settings</h4>
        <ul class="nav flex-column">
            @foreach (var section in _sections)
            {
                <li class="nav-item">
                    <button class="nav-link @(ActiveSection == section.Key ? "active" : "")"
                            @onclick="() => SetActiveSection(section.Key)">
                        <span class="section-icon">@section.Value.Icon</span>
                        @section.Value.Label
                    </button>
                </li>
            }
        </ul>
    </nav>

    <main class="settings-content">
        @if (_loading)
        {
            <div class="d-flex justify-content-center p-5">
                <div class="spinner-border text-primary" role="status">
                    <span class="visually-hidden">Loading...</span>
                </div>
            </div>
        }
        else
        {
            @switch (ActiveSection)
            {
                case "profile":
                    @RenderProfileSection()
                    break;
                case "notifications":
                    @RenderNotificationsSection()
                    break;
                case "security":
                    @RenderSecuritySection()
                    break;
                case "appearance":
                    @RenderAppearanceSection()
                    break;
            }
        }

        @if (!string.IsNullOrEmpty(_toastMessage))
        {
            <div class="settings-toast @(_toastIsError ? "toast-error" : "toast-success")">
                <span>@_toastMessage</span>
                <button class="btn-close btn-close-white btn-sm" @onclick="DismissToast"></button>
            </div>
        }
    </main>
</div>

@* ───── Profile Section ───── *@
@{
    RenderFragment RenderProfileSection() =>
        @<section class="settings-section">
            <h3>Profile</h3>
            <p class="text-muted">Manage your public profile information.</p>
            <hr />

            <div class="avatar-area mb-4">
                <div class="avatar-preview">
                    @if (!string.IsNullOrWhiteSpace(_profileAvatarUrl))
                    {
                        <img src="@_profileAvatarUrl" alt="Avatar" />
                    }
                    else
                    {
                        <span class="avatar-placeholder">👤</span>
                    }
                </div>
                <div class="avatar-url-display">
                    <label class="form-label">Avatar URL</label>
                    <input type="url" class="form-control" value="@_profileAvatarUrl"
                           @oninput="e => _profileAvatarUrl = e.Value?.ToString() ?? string.Empty" />
                </div>
            </div>

            <div class="mb-3">
                <label class="form-label">Display Name</label>
                <input type="text" class="form-control" @bind="_profileDisplayName" />
            </div>
            <div class="mb-3">
                <label class="form-label">Email</label>
                <input type="email" class="form-control" @bind="_profileEmail" />
            </div>
            <div class="mb-3">
                <label class="form-label">Bio</label>
                <textarea class="form-control" rows="4" @bind="_profileBio"></textarea>
            </div>

            <div class="d-flex gap-2">
                <button class="btn btn-primary" @onclick="SaveProfile" disabled="@_saving">
                    @if (_saving) { <span class="spinner-border spinner-border-sm me-1"></span> }
                    Save Changes
                </button>
                <button class="btn btn-outline-secondary" @onclick="DiscardProfileChanges" disabled="@_saving">
                    Discard Changes
                </button>
            </div>
        </section>;
}

@* ───── Notifications Section ───── *@
@{
    RenderFragment RenderNotificationsSection() =>
        @<section class="settings-section">
            <h3>Notifications</h3>
            <p class="text-muted">Choose how and when you want to be notified.</p>
            <hr />

            <div class="toggle-row">
                <div>
                    <strong>Email Notifications</strong>
                    <p class="text-muted mb-0">Receive updates via email.</p>
                </div>
                <div class="form-check form-switch">
                    <input class="form-check-input" type="checkbox" role="switch"
                           checked="@_notifEmail" @onchange="e => _notifEmail = (bool)(e.Value ?? false)" />
                </div>
            </div>
            <div class="toggle-row">
                <div>
                    <strong>Push Notifications</strong>
                    <p class="text-muted mb-0">Receive browser push notifications.</p>
                </div>
                <div class="form-check form-switch">
                    <input class="form-check-input" type="checkbox" role="switch"
                           checked="@_notifPush" @onchange="e => _notifPush = (bool)(e.Value ?? false)" />
                </div>
            </div>
            <div class="toggle-row">
                <div>
                    <strong>Weekly Digest</strong>
                    <p class="text-muted mb-0">Get a summary email every week.</p>
                </div>
                <div class="form-check form-switch">
                    <input class="form-check-input" type="checkbox" role="switch"
                           checked="@_notifDigest" @onchange="e => _notifDigest = (bool)(e.Value ?? false)" />
                </div>
            </div>

            <h5 class="mt-4 mb-3">Muted Channels</h5>
            @if (_allChannels.Count > 0)
            {
                <div class="channel-list">
                    @foreach (var channel in _allChannels)
                    {
                        var isMuted = _mutedChannels.Contains(channel);
                        <div class="form-check">
                            <input class="form-check-input" type="checkbox" id="ch-@channel"
                                   checked="@isMuted"
                                   @onchange="e => ToggleMuteChannel(channel, (bool)(e.Value ?? false))" />
                            <label class="form-check-label" for="ch-@channel">@channel</label>
                        </div>
                    }
                </div>
            }
            else
            {
                <p class="text-muted fst-italic">No channels available.</p>
            }

            <div class="mt-4">
                <button class="btn btn-primary" @onclick="SaveNotifications" disabled="@_saving">
                    @if (_saving) { <span class="spinner-border spinner-border-sm me-1"></span> }
                    Save Preferences
                </button>
            </div>
        </section>;
}

@* ───── Security Section ───── *@
@{
    RenderFragment RenderSecuritySection() =>
        @<section class="settings-section">
            <h3>Security</h3>
            <p class="text-muted">Manage your password, two-factor authentication, and sessions.</p>
            <hr />

            @* Change Password Panel *@
            <div class="expandable-panel mb-4">
                <button class="expandable-header" @onclick="() => _passwordPanelOpen = !_passwordPanelOpen">
                    <span>🔑 Change Password</span>
                    <span class="expand-icon">@(_passwordPanelOpen ? "▲" : "▼")</span>
                </button>
                @if (_passwordPanelOpen)
                {
                    <div class="expandable-body">
                        <div class="mb-3">
                            <label class="form-label">Current Password</label>
                            <input type="password" class="form-control" @bind="_currentPassword" />
                        </div>
                        <div class="mb-3">
                            <label class="form-label">New Password</label>
                            <input type="password" class="form-control" @bind="_newPassword" />
                        </div>
                        <div class="mb-3">
                            <label class="form-label">Confirm New Password</label>
                            <input type="password" class="form-control" @bind="_confirmPassword" />
                        </div>
                        <button class="btn btn-warning" @onclick="ChangePassword" disabled="@_saving">
                            @if (_saving) { <span class="spinner-border spinner-border-sm me-1"></span> }
                            Update Password
                        </button>
                    </div>
                }
            </div>

            @* Two-Factor Authentication *@
            <div class="toggle-row mb-4">
                <div>
                    <strong>Two-Factor Authentication</strong>
                    <p class="text-muted mb-0">
                        Status:
                        <span class="badge @(_twoFactorEnabled ? "bg-success" : "bg-secondary")">
                            @(_twoFactorEnabled ? "Enabled" : "Disabled")
                        </span>
                    </p>
                </div>
                <div class="form-check form-switch">
                    <input class="form-check-input" type="checkbox" role="switch"
                           checked="@_twoFactorEnabled"
                           @onchange="e => _twoFactorEnabled = (bool)(e.Value ?? false)" />
                </div>
            </div>

            @if (_securitySettings?.LastPasswordChange is not null)
            {
                <p class="text-muted">
                    <small>Last password change: @_securitySettings.LastPasswordChange.Value.ToString("MMMM dd, yyyy")</small>
                </p>
            }

            @* Active Sessions *@
            <h5 class="mt-4 mb-3">Active Sessions</h5>
            @if (_sessions.Count > 0)
            {
                <div class="table-responsive">
                    <table class="table table-hover align-middle">
                        <thead class="table-light">
                            <tr>
                                <th>Device</th>
                                <th>Location</th>
                                <th>Last Active</th>
                                <th></th>
                            </tr>
                        </thead>
                        <tbody>
                            @foreach (var session in _sessions)
                            {
                                var isCurrent = session == _sessions.FirstOrDefault();
                                <tr>
                                    <td>
                                        @session.Device
                                        @if (isCurrent) { <span class="badge bg-info ms-1">Current</span> }
                                    </td>
                                    <td>@session.Location</td>
                                    <td>@session.LastActive.ToString("g")</td>
                                    <td>
                                        @if (!isCurrent)
                                        {
                                            <button class="btn btn-outline-danger btn-sm"
                                                    @onclick="() => PromptRevokeSession(session)">
                                                Revoke
                                            </button>
                                        }
                                    </td>
                                </tr>
                            }
                        </tbody>
                    </table>
                </div>
            }
            else
            {
                <p class="text-muted fst-italic">No active sessions found.</p>
            }

            @* Revoke Confirmation Dialog *@
            @if (_sessionToRevoke is not null)
            {
                <div class="modal-backdrop-custom" @onclick="CancelRevoke">
                    <div class="confirm-dialog" @onclick:stopPropagation="true">
                        <h5>Revoke Session</h5>
                        <p>Are you sure you want to revoke the session on <strong>@_sessionToRevoke.Device</strong> in <strong>@_sessionToRevoke.Location</strong>?</p>
                        <div class="d-flex gap-2 justify-content-end">
                            <button class="btn btn-outline-secondary btn-sm" @onclick="CancelRevoke">Cancel</button>
                            <button class="btn btn-danger btn-sm" @onclick="ConfirmRevokeSession" disabled="@_saving">
                                @if (_saving) { <span class="spinner-border spinner-border-sm me-1"></span> }
                                Revoke
                            </button>
                        </div>
                    </div>
                </div>
            }
        </section>;
}

@* ───── Appearance Section ───── *@
@{
    RenderFragment RenderAppearanceSection() =>
        @<section class="settings-section">
            <h3>Appearance</h3>
            <p class="text-muted">Customize how the application looks and feels.</p>
            <hr />

            <div class="row">
                <div class="col-md-7">
                    @* Theme *@
                    <h5 class="mb-3">Theme</h5>
                    <div class="d-flex gap-3 mb-4">
                        @foreach (var theme in new[] { "Light", "Dark", "System" })
                        {
                            <div class="form-check">
                                <input class="form-check-input" type="radio" name="theme" id="theme-@theme"
                                       value="@theme" checked="@(_appearanceTheme == theme)"
                                       @onchange="() => _appearanceTheme = theme" />
                                <label class="form-check-label" for="theme-@theme">@theme</label>
                            </div>
                        }
                    </div>

                    @* Font Size *@
                    <h5 class="mb-3">Font Size</h5>
                    <div class="d-flex gap-3 mb-4">
                        @foreach (var size in new[] { "Small", "Medium", "Large" })
                        {
                            <div class="form-check">
                                <input class="form-check-input" type="radio" name="fontSize" id="fs-@size"
                                       value="@size" checked="@(_appearanceFontSize == size)"
                                       @onchange="() => _appearanceFontSize = size" />
                                <label class="form-check-label" for="fs-@size">@size</label>
                            </div>
                        }
                    </div>

                    @* Language *@
                    <div class="mb-4">
                        <h5 class="mb-3">Language</h5>
                        <select class="form-select" style="max-width: 300px;"
                                value="@_appearanceLanguage"
                                @onchange="e => _appearanceLanguage = e.Value?.ToString() ?? "English"">
                            @foreach (var lang in _availableLanguages)
                            {
                                <option value="@lang">@lang</option>
                            }
                        </select>
                    </div>

                    @* Compact Mode *@
                    <div class="toggle-row mb-4">
                        <div>
                            <strong>Compact Mode</strong>
                            <p class="text-muted mb-0">Reduce spacing and padding throughout the UI.</p>
                        </div>
                        <div class="form-check form-switch">
                            <input class="form-check-input" type="checkbox" role="switch"
                                   checked="@_appearanceCompact"
                                   @onchange="e => _appearanceCompact = (bool)(e.Value ?? false)" />
                        </div>
                    </div>

                    <button class="btn btn-primary" @onclick="SaveAppearance" disabled="@_saving">
                        @if (_saving) { <span class="spinner-border spinner-border-sm me-1"></span> }
                        Save
                    </button>
                </div>

                @* Live Preview *@
                <div class="col-md-5">
                    <h5 class="mb-3">Preview</h5>
                    <div class="appearance-preview @GetPreviewClasses()">
                        <div class="preview-header">Header</div>
                        <div class="preview-body">
                            <p class="preview-text">This is a preview of your selected appearance settings.</p>
                            <button class="preview-button">Sample Button</button>
                        </div>
                        <div class="preview-footer">Footer</div>
                    </div>
                </div>
            </div>
        </section>;
}

@code {
    // ───── Section navigation ─────
    private string ActiveSection { get; set; } = "profile";
    private bool _loading = true;
    private bool _saving;

    private readonly Dictionary<string, (string Label, string Icon)> _sections = new()
    {
        ["profile"] = ("Profile", "👤"),
        ["notifications"] = ("Notifications", "🔔"),
        ["security"] = ("Security", "🛡️"),
        ["appearance"] = ("Appearance", "🎨")
    };

    // ───── Toast ─────
    private string? _toastMessage;
    private bool _toastIsError;
    private CancellationTokenSource? _toastCts;

    // ───── Profile state ─────
    private string _profileDisplayName = string.Empty;
    private string _profileEmail = string.Empty;
    private string _profileAvatarUrl = string.Empty;
    private string _profileBio = string.Empty;
    private UserProfile? _savedProfile;

    // ───── Notifications state ─────
    private bool _notifEmail;
    private bool _notifPush;
    private bool _notifDigest;
    private HashSet<string> _mutedChannels = new();
    private readonly List<string> _allChannels = new()
    {
        "general", "announcements", "engineering", "design", "marketing", "random", "support"
    };

    // ───── Security state ─────
    private SecuritySettings? _securitySettings;
    private bool _passwordPanelOpen;
    private string _currentPassword = string.Empty;
    private string _newPassword = string.Empty;
    private string _confirmPassword = string.Empty;
    private bool _twoFactorEnabled;
    private List<ActiveSession> _sessions = new();
    private ActiveSession? _sessionToRevoke;

    // ───── Appearance state ─────
    private string _appearanceTheme = "System";
    private string _appearanceFontSize = "Medium";
    private string _appearanceLanguage = "English";
    private bool _appearanceCompact;
    private readonly List<string> _availableLanguages = new()
    {
        "English", "Spanish", "French", "German", "Japanese", "Chinese", "Korean", "Portuguese"
    };

    protected override async Task OnInitializedAsync()
    {
        await LoadAllSettings();
        _loading = false;
    }

    private async Task LoadAllSettings()
    {
        var profileTask = SettingsService.GetProfileAsync();
        var notifTask = SettingsService.GetNotificationPrefsAsync();
        var securityTask = SettingsService.GetSecuritySettingsAsync();
        var appearanceTask = SettingsService.GetAppearanceAsync();

        await Task.WhenAll(profileTask, notifTask, securityTask, appearanceTask);

        ApplyProfile(await profileTask);
        ApplyNotifications(await notifTask);
        ApplySecurity(await securityTask);
        ApplyAppearance(await appearanceTask);
    }

    // ───── Section switching ─────
    private void SetActiveSection(string section) => ActiveSection = section;

    // ───── Profile ─────
    private void ApplyProfile(UserProfile profile)
    {
        _savedProfile = profile;
        _profileDisplayName = profile.DisplayName;
        _profileEmail = profile.Email;
        _profileAvatarUrl = profile.AvatarUrl;
        _profileBio = profile.Bio;
    }

    private async Task SaveProfile()
    {
        _saving = true;
        try
        {
            var profile = new UserProfile(_profileDisplayName, _profileEmail, _profileAvatarUrl, _profileBio);
            await SettingsService.SaveProfileAsync(profile);
            _savedProfile = profile;
            ShowToast("Profile saved successfully.");
        }
        catch (Exception ex)
        {
            ShowToast($"Failed to save profile: {ex.Message}", isError: true);
        }
        finally
        {
            _saving = false;
        }
    }

    private void DiscardProfileChanges()
    {
        if (_savedProfile is not null)
        {
            ApplyProfile(_savedProfile);
        }
    }

    // ───── Notifications ─────
    private void ApplyNotifications(NotificationPrefs prefs)
    {
        _notifEmail = prefs.EmailNotifications;
        _notifPush = prefs.PushNotifications;
        _notifDigest = prefs.WeeklyDigest;
        _mutedChannels = new HashSet<string>(prefs.MutedChannels);
    }

    private void ToggleMuteChannel(string channel, bool muted)
    {
        if (muted)
            _mutedChannels.Add(channel);
        else
            _mutedChannels.Remove(channel);
    }

    private async Task SaveNotifications()
    {
        _saving = true;
        try
        {
            var prefs = new NotificationPrefs(_notifEmail, _notifPush, _notifDigest, _mutedChannels.ToList());
            await SettingsService.SaveNotificationPrefsAsync(prefs);
            ShowToast("Notification preferences saved.");
        }
        catch (Exception ex)
        {
            ShowToast($"Failed to save preferences: {ex.Message}", isError: true);
        }
        finally
        {
            _saving = false;
        }
    }

    // ───── Security ─────
    private void ApplySecurity(SecuritySettings settings)
    {
        _securitySettings = settings;
        _twoFactorEnabled = settings.TwoFactorEnabled;
        _sessions = new List<ActiveSession>(settings.Sessions);
    }

    private async Task ChangePassword()
    {
        if (string.IsNullOrWhiteSpace(_currentPassword) ||
            string.IsNullOrWhiteSpace(_newPassword) ||
            string.IsNullOrWhiteSpace(_confirmPassword))
        {
            ShowToast("All password fields are required.", isError: true);
            return;
        }

        if (_newPassword != _confirmPassword)
        {
            ShowToast("New password and confirmation do not match.", isError: true);
            return;
        }

        _saving = true;
        try
        {
            await SettingsService.ChangePasswordAsync(_currentPassword, _newPassword);
            _currentPassword = string.Empty;
            _newPassword = string.Empty;
            _confirmPassword = string.Empty;
            _passwordPanelOpen = false;
            ShowToast("Password updated successfully.");
        }
        catch (Exception ex)
        {
            ShowToast($"Failed to change password: {ex.Message}", isError: true);
        }
        finally
        {
            _saving = false;
        }
    }

    private void PromptRevokeSession(ActiveSession session) => _sessionToRevoke = session;

    private void CancelRevoke() => _sessionToRevoke = null;

    private async Task ConfirmRevokeSession()
    {
        if (_sessionToRevoke is null) return;

        _saving = true;
        try
        {
            await SettingsService.RevokeSessionAsync(_sessionToRevoke.Id);
            _sessions.Remove(_sessionToRevoke);
            ShowToast($"Session on {_sessionToRevoke.Device} revoked.");
            _sessionToRevoke = null;
        }
        catch (Exception ex)
        {
            ShowToast($"Failed to revoke session: {ex.Message}", isError: true);
        }
        finally
        {
            _saving = false;
        }
    }

    // ───── Appearance ─────
    private void ApplyAppearance(AppearanceSettings settings)
    {
        _appearanceTheme = settings.Theme;
        _appearanceFontSize = settings.FontSize;
        _appearanceLanguage = settings.Language;
        _appearanceCompact = settings.CompactMode;
    }

    private async Task SaveAppearance()
    {
        _saving = true;
        try
        {
            var settings = new AppearanceSettings(_appearanceTheme, _appearanceFontSize, _appearanceLanguage, _appearanceCompact);
            await SettingsService.SaveAppearanceAsync(settings);
            ShowToast("Appearance settings saved.");
        }
        catch (Exception ex)
        {
            ShowToast($"Failed to save appearance: {ex.Message}", isError: true);
        }
        finally
        {
            _saving = false;
        }
    }

    private string GetPreviewClasses()
    {
        var classes = new List<string>();
        classes.Add(_appearanceTheme switch
        {
            "Dark" => "preview-dark",
            "Light" => "preview-light",
            _ => "preview-system"
        });
        classes.Add(_appearanceFontSize switch
        {
            "Small" => "preview-font-sm",
            "Large" => "preview-font-lg",
            _ => "preview-font-md"
        });
        if (_appearanceCompact) classes.Add("preview-compact");
        return string.Join(" ", classes);
    }

    // ───── Toast helpers ─────
    private void ShowToast(string message, bool isError = false)
    {
        _toastCts?.Cancel();
        _toastMessage = message;
        _toastIsError = isError;
        _toastCts = new CancellationTokenSource();
        _ = AutoDismissToast(_toastCts.Token);
    }

    private async Task AutoDismissToast(CancellationToken token)
    {
        try
        {
            await Task.Delay(4000, token);
            _toastMessage = null;
            await InvokeAsync(StateHasChanged);
        }
        catch (TaskCanceledException) { }
    }

    private void DismissToast()
    {
        _toastCts?.Cancel();
        _toastMessage = null;
    }
}
