    align-items: flex-start;
    gap: 1.5rem;
}

.avatar-preview {
    width: 96px;
    height: 96px;
    border-radius: 50%;
    overflow: hidden;
    border: 2px solid #dee2e6;
    display: flex;
    align-items: center;
    justify-content: center;
    background: #f0f0f0;
    flex-shrink: 0;
}

.avatar-preview img {
    width: 100%;
    height: 100%;
    object-fit: cover;
}

.avatar-placeholder {
    font-size: 2.5rem;
}

.avatar-url-display {
    flex: 1;
    min-width: 0;
}

/* ───── Channel list ───── */
.channel-list {
    display: grid;
    grid-template-columns: repeat(auto-fill, minmax(180px, 1fr));
    gap: 0.25rem 1rem;
}

/* ───── Expandable panel ───── */
.expandable-panel {
    border: 1px solid #dee2e6;
    border-radius: 0.5rem;
    overflow: hidden;
}

.expandable-header {
    display: flex;
    justify-content: space-between;
    align-items: center;
    width: 100%;
    padding: 0.85rem 1rem;
    background: #f8f9fa;
    border: none;
    font-size: 1rem;
    font-weight: 500;
    cursor: pointer;
    transition: background-color 0.15s;
}

.expandable-header:hover {
    background: #e9ecef;
}

.expand-icon {
    font-size: 0.8rem;
    color: #6c757d;
}

.expandable-body {
    padding: 1rem;
