+    height: 96px;
+    border-radius: 50%;
+    overflow: hidden;
+    border: 2px solid #dee2e6;
+    display: flex;
+    align-items: center;
+    justify-content: center;
+    background: #f0f0f0;
+    flex-shrink: 0;
+}
+
+.avatar-preview img {
+    width: 100%;
+    height: 100%;
+    object-fit: cover;
+}
+
+.avatar-placeholder {
+    font-size: 2.5rem;
+}
+
+.avatar-url-display {
+    flex: 1;
+    min-width: 0;
+}
+
+/* ───── Channel list ───── */
+.channel-list {
+    display: grid;
+    grid-template-columns: repeat(auto-fill, minmax(180px, 1fr));
+    gap: 0.25rem 1rem;
+}
+
+/* ───── Expandable panel ───── */
+.expandable-panel {
+    border: 1px solid #dee2e6;
+    border-radius: 0.5rem;
+    overflow: hidden;
+}
+
+.expandable-header {
+    display: flex;
+    justify-content: space-between;
+    align-items: center;
+    width: 100%;
+    padding: 0.85rem 1rem;
+    background: #f8f9fa;
+    border: none;
+    font-size: 1rem;
+    font-weight: 500;
+    cursor: pointer;
+    transition: background-color 0.15s;
+}
+
+.expandable-header:hover {
+    background: #e9ecef;
+}
+
+.expand-icon {
+    font-size: 0.8rem;
+    color: #6c757d;
+}
+
+.expandable-body {
+    padding: 1rem;
+    border-top: 1px solid #dee2e6;
+}
+
+/* ───── Confirmation dialog ───── */
+.modal-backdrop-custom {
+    position: fixed;
+    inset: 0;
+    background: rgba(0, 0, 0, 0.4);
+    display: flex;
+    align-items: center;
+    justify-content: center;
+    z-index: 1050;
+}
+
+.confirm-dialog {
+    background: white;
+    padding: 1.5rem;
+    border-radius: 0.5rem;
+    box-shadow: 0 8px 32px rgba(0, 0, 0, 0.2);
+    max-width: 420px;
+    width: 90%;
+}
+
+/* ───── Toast ───── */
+.settings-toast {
+    position: fixed;
+    bottom: 1.5rem;
+    right: 1.5rem;
+    padding: 0.75rem 1.25rem;
+    border-radius: 0.5rem;
+    color: white;
+    display: flex;
+    align-items: center;
+    gap: 0.75rem;
+    box-shadow: 0 4px 16px rgba(0, 0, 0, 0.15);
+    z-index: 1100;
+    animation: toast-slide-in 0.3s ease;
+}
+
+.toast-success {
+    background: #198754;
+}
+
+.toast-error {
+    background: #dc3545;
+}
+
+@keyframes toast-slide-in {
+    from {
+        transform: translateY(1rem);
+        opacity: 0;
+    }
+    to {
+        transform: translateY(0);
+        opacity: 1;
+    }
+}
+
+/* ───── Appearance preview ───── */
+.appearance-preview {
+    border: 1px solid #dee2e6;
+    border-radius: 0.5rem;
+    overflow: hidden;
+    transition: all 0.2s ease;
+}
+
+.preview-header {
+    padding: 0.75rem 1rem;
+    font-weight: 600;
+    border-bottom: 1px solid #dee2e6;
+}
+
+.preview-body {
+    padding: 1rem;
+}
+
+.preview-footer {
+    padding: 0.5rem 1rem;
+    border-top: 1px solid #dee2e6;
+    font-size: 0.85em;
+}
+
+.preview-button {
+    padding: 0.35rem 1rem;
+    border-radius: 0.35rem;
+    border: 1px solid #0d6efd;
+    background: #0d6efd;
+    color: white;
+    cursor: default;
+}
+
+/* Theme variants */
+.preview-light {
+    background: #ffffff;
+    color: #212529;
+}
+
+.preview-light .preview-header {
+    background: #f8f9fa;
+}
+
+.preview-light .preview-footer {
+    background: #f8f9fa;
+}
+
+.preview-dark {
+    background: #1e1e2e;
+    color: #cdd6f4;
+    border-color: #45475a;
+}
+
+.preview-dark .preview-header {
+    background: #181825;
+    border-color: #45475a;
+}
+
+.preview-dark .preview-footer {
+    background: #181825;
+    border-color: #45475a;
+}
+
+.preview-dark .preview-button {
+    background: #89b4fa;
+    border-color: #89b4fa;
+    color: #1e1e2e;
+}
+
+.preview-system {
+    background: linear-gradient(135deg, #ffffff 50%, #1e1e2e 50%);
+    color: #212529;
+}
+
+.preview-system .preview-header {
+    background: #f8f9fa;
+}
+
+.preview-system .preview-footer {
+    background: #f8f9fa;
+}
+
+/* Font size variants */
+.preview-font-sm {
+    font-size: 0.8rem;
+}
+
+.preview-font-md {
+    font-size: 1rem;
+}
+
+.preview-font-lg {
+    font-size: 1.2rem;
+}
+
+/* Compact mode */
+.preview-compact .preview-header {
+    padding: 0.4rem 0.75rem;
+}
+
+.preview-compact .preview-body {
+    padding: 0.5rem 0.75rem;
+}
+
+.preview-compact .preview-footer {
+    padding: 0.25rem 0.75rem;
+}
+
+.preview-compact .preview-text {
+    margin-bottom: 0.25rem;
+}
+
